| **预计工作量** | 2-3 小时 |
| **复杂度** | 低 |
| **风险等级** | 极低 |

### 核心问题

1. **配置分散**：配置散落在多个文件中（server.ts、.env、各个 service）
2. **缺少验证**：环境变量没有类型检查和验证
3. **缺少默认值**：某些配置缺少合理的默认值
4. **文档不足**：配置项缺少集中的文档说明

### 技术方案

#### 1. 创建统一的配置管理模块

```typescript
// src/config/dashboard.config.ts
interface DashboardConfigSchema {
  // 服务器配置
  server: {
    port: number;
    host: string;
    corsOrigin: string;
  };

  // 数据库配置
  database: {
    path: string;
    maxConnections?: number;
  };

  // 日志配置
  logging: {
    level: 'fatal' | 'error' | 'warn' | 'info' | 'debug' | 'trace';
    prettyPrint: boolean;
  };

  // WebSocket 配置
  websocket: {
    heartbeatInterval: number;
    maxConnections?: number;
  };

  // 性能监控配置
  metrics: {
    enabled: boolean;
    interval: number;
  };
}

export class DashboardConfig {
  private static instance: DashboardConfigSchema;

  static load(): DashboardConfigSchema {
    if (this.instance) return this.instance;

    this.instance = {
      server: {
        port: this.parseEnv('DASHBOARD_PORT', 3000, 'number'),
        host: this.parseEnv('DASHBOARD_HOST', '0.0.0.0', 'string'),
        corsOrigin: this.parseEnv('CORS_ORIGIN', 'http://localhost:5173', 'string'),
      },
      database: {
        path: this.parseEnv('DATABASE_PATH', './database/dashboard.db', 'string'),
      },
      logging: {
        level: this.parseEnv('LOG_LEVEL', 'info', 'enum', ['fatal', 'error', 'warn', 'info', 'debug', 'trace']),
        prettyPrint: this.parseEnv('LOG_PRETTY_PRINT', 'true', 'boolean'),
      },
      websocket: {
        heartbeatInterval: this.parseEnv('WS_HEARTBEAT', 30, 'number'),
      },
      metrics: {
        enabled: this.parseEnv('ENABLE_METRICS', 'true', 'boolean'),
        interval: this.parseEnv('METRICS_INTERVAL', 30, 'number'),
      },
    };

    return this.instance;
  }

  private static parseEnv<T>(
    key: string, 
    defaultValue: T, 
    type: 'string' | 'number' | 'boolean' | 'enum',
    enumValues?: string[]
  ): T {
    const value = process.env[key];

    if (value === undefined) return defaultValue;

    switch (type) {
      case 'number':
        const num = parseInt(value, 10);
        if (isNaN(num)) {
          console.warn(`Invalid ${key}: "${value}" is not a number, using default: ${defaultValue}`);
          return defaultValue;
        }
        return num as T;

      case 'boolean':
        if (value === 'true') return true as T;
        if (value === 'false') return false as T;
        console.warn(`Invalid ${key}: "${value}" is not a boolean, using default: ${defaultValue}`);
        return defaultValue;

      case 'enum':
        if (enumValues && enumValues.includes(value)) {
          return value as T;
        }
        console.warn(`Invalid ${key}: "${value}" is not one of ${enumValues?.join(', ')}, using default: ${defaultValue}`);
        return defaultValue;

      case 'string':
      default:
        return value as T;
    }
  }

  static validate(): boolean {
    const config = this.load();

    // 验证端口范围
    if (config.server.port < 1 || config.server.port > 65535) {
      console.error('Invalid port: must be between 1 and 65535');
      return false;
    }

    // 验证日志级别
    const validLevels = ['fatal', 'error', 'warn', 'info', 'debug', 'trace'];
    if (!validLevels.includes(config.logging.level)) {
      console.error(`Invalid log level: ${config.logging.level}`);
      return false;
    }

    return true;
  }
}
```

